if(!([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)){Start-Process powershell.exe "-NoProfile -ExecutionPolicy Bypass -File `"$PSCommandPath`"" -Verb RunAs;Exit}; $r="HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\SystemRestore"; if(!(Test-Path $r)){New-Item $r -Force | Out-Null}; New-ItemProperty -Path $r -Name "SystemRestorePointCreationFrequency" -Value 0 -PropertyType DWord -Force -EA 0 | Out-Null; Write-Host "Checking Drive and Creating Restore Point..."; try{Enable-ComputerRestore -Drive $Env:SystemDrive -EA Stop; Checkpoint-Computer -Description "RestorePoint_PS" -RestorePointType MODIFY_SETTINGS -EA Stop; Write-Host "[Success] Restore Point Created."}catch{Write-Host "[Error] $($_.Exception.Message)"}; Write-Host "Press any key to exit..."; $null=$Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")